(function($){"use strict";if(window._tableSortInit)return;window._tableSortInit=true;$(function(){$("th[data-sort-type]").each(function(){var $th=$(this);if($th.data("sort-type")==="none")return;$th.addClass("sortable")});$("th.sortable").on("click",function(e){if($(e.target).hasClass("col-filter"))return;var $th=$(this),table=$th.closest("table")[0],tbody=table.tBodies[0];if(!tbody)return;var colIdx=$th.index(),type=$th.data("sort-type")||"text",asc=!$th.hasClass("sort-asc");$th.closest("tr").find("th").removeClass("sort-asc sort-desc");$th.addClass(asc?"sort-asc":"sort-desc");var rows=Array.prototype.slice.call(tbody.rows);rows.sort(function(a,b){var cellA=a.cells[colIdx],cellB=b.cells[colIdx],valA=(cellA?cellA.textContent:"").trim(),valB=(cellB?cellB.textContent:"").trim(),cmp=compare(valA,valB,type);return asc?cmp:-cmp});for(var i=0;i<rows.length;i++)tbody.appendChild(rows[i])});$("table").has("th.sortable").each(function(){var $table=$(this),$thead=$table.find("thead"),$headerRow=$thead.find("tr").first(),$filterRow=$('<tr class="filter-row no-print"></tr>');$headerRow.find("th").each(function(){var $th=$(this),sortType=$th.data("sort-type"),$td=$("<td></td>");if(sortType&&sortType!=="none"){var $input=$('<input type="text" class="col-filter form-control form-control-sm" placeholder="Filter...">');$input.on("input",function(){applyFilters($table)});$td.append($input)}$filterRow.append($td)});$thead.append($filterRow)})});function applyFilters($table){var filters=[];$table.find(".filter-row .col-filter").each(function(){var $input=$(this),colIdx=$input.closest("td").index(),val=$input.val().toLowerCase().trim();if(val)filters.push({col:colIdx,text:val})});$table.find("tbody tr").each(function(){var $row=$(this),show=true;for(var i=0;i<filters.length;i++){var cell=$row[0].cells[filters[i].col],cellText=(cell?cell.textContent:"").toLowerCase();if(cellText.indexOf(filters[i].text)===-1){show=false;break}}$row.toggle(show)})}function compare(a,b,type){switch(type){case"number":case"price":return toNumber(a)-toNumber(b);case"date-de":return parseDateDe(a)-parseDateDe(b);default:return a.localeCompare(b,"de",{sensitivity:"base"})}}function toNumber(s){s=s.replace(/[^\d.,\-]/g,"");s=s.replace(/\./g,"");s=s.replace(",",".");var n=parseFloat(s);return isNaN(n)?0:n}function parseDateDe(s){var m=s.match(/(\d{2})\.(\d{2})\.(\d{4})/);if(!m)return 0;var d=new Date(parseInt(m[3],10),parseInt(m[2],10)-1,parseInt(m[1],10));var t=s.match(/(\d{2}):(\d{2})/);if(t)d.setHours(parseInt(t[1],10),parseInt(t[2],10));return d.getTime()}})(jQuery);
